INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('gauss_sphere_surface_state_sweeps_past_R_should_stop_at_surface', 'The "at the surface" continuity state sweeps the Gaussian sphere OUTSIDE R instead of stopping at the surface to explain', 'MAJOR', 'alex:json_author', 'gauss_law_solid_sphere STATE_5 (the surface-continuity beat) used a coordinated_sweep with sweep_r_max=1.95 (> R=1.5), so the Gaussian sphere + radial arrows continued OUTSIDE the surface — cluttering the moment that should simply hold AT the surface and explain that the inside ramp and the outside 1/r² meet at kq/R². Founder (screen recording): "it should stop just at the surface… you are moving outside the surface… you should not… only till surface and explain it… a lot of things going on, please remove this."', 'A "at the surface" / continuity beat must hold the Gaussian sphere AT r=R (sweep_r_max = R, or no sweep at all) and explain there. Sweeping past the surface belongs ONLY to the full-profile state (the one that draws the whole E-vs-r curve), never to the surface-explanation state.', 'manual', 'Open the surface-continuity state; the Gaussian sphere must approach and HOLD at the red surface (r=R), never grow visibly larger than the charged sphere.', 'FIXED', ARRAY['gauss_law_solid_sphere'], ARRAY['src/data/concepts/gauss_law_solid_sphere.json'], 'session_2026-06-26_gauss_solid_founder_review', 'incident'),
('gsph_radius_R_line_not_anchored_at_sphere_centre', 'The big R radius line is lifted above the sphere centre (staggered up) instead of starting from the actual centre; R and r read as one line', 'MAJOR', 'peter_parker:renderer_primitives', 'In the gauss-sphere scenario the R position vector is billboarded at +camUp·R_STAGGER (0.45 above the equator), so it does not pass through the sphere centre, and the small r line sits just under it — the two read as the same line offset from centre. Founder (screen recording): "the radius… is not in the center… show from the center, this is capital R… show the small radius not in the same line… the big R radius line should be at the center of the actual sphere."', 'The big R radius line must originate at the sphere CENTRE (on the centre/equator line, no upward offset) so it visibly runs centre→surface; only the smaller r line is staggered clearly off-centre so the two read as two distinct radius lines.', 'manual', 'Inspect any state showing the R radius line; its tail must sit at the sphere centre with the line passing through the centre to the surface, and the r line must be a clearly separate parallel line — not coincident with R.', 'FIXED', ARRAY['gauss_law_solid_sphere', 'gauss_law_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_solid_founder_review', 'incident'),
('gsph_small_r_radius_line_horizontal_should_be_angled_from_centre', 'The small r (Gaussian-sphere) radius line is horizontal; it should be a diagonal radius from the centre whose tip rides the moving Gaussian surface', 'MAJOR', 'peter_parker:renderer_primitives', 'The r position-vector is billboarded horizontal (along camRight) and staggered below the centre, so on the dynamic Gaussian states (shrink/sweep/slider) it reads as a second horizontal line sliding left-right, not as a radius sweeping the moving surface from the centre. Founder (screen recording): "the small r should not be horizontal — it should be at an angle from the centre, so as the Gaussian sphere increases/decreases the small r line increases/decreases… it feels like it is moving along the surface and coming from the centre. Solve in all states, in both the hollow and solid sphere sims."', 'On a dynamic Gaussian-sphere scenario the small r radius line must be a DIAGONAL radius FROM THE CENTRE (e.g. ~35° down-right in screen space) whose tip rides the Gaussian silhouette (length = r_gauss), so it tracks the surface as the sphere grows/shrinks; only the static big R line stays horizontal-from-centre.', 'manual', 'Open any dynamic Gaussian state (shrink/sweep/slider) in either sim; the small r line must run diagonally from the sphere centre to a point on the Gaussian surface, with the P dot on the silhouette, and as r changes the tip must slide along the surface — not stay a horizontal line.', 'FIXED', ARRAY['gauss_law_sphere', 'gauss_law_solid_sphere'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_solid_founder_review', 'incident')
